using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" }
        }
    };

    [Description("Search the web for a query and return a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        try
        {
            var html = await _http.GetStringAsync(url);
            var results = ParseResults(html);

            if (results.Count == 0)
                return "No results found.";

            return string.Join("\n\n", results.Take(5).Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Useful for reading full articles.")]
    public async Task<string> FetchPage(
        [Description("The URL to fetch")] string url)
    {
        try
        {
            var html = await _http.GetStringAsync(url);

            // Strip tags and decode entities for a rough plaintext extraction
            var text = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<style[^>]*>[\s\S]*?</style>", " ", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, @"<[^>]+>", " ");
            text = WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLen = 6000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "... [truncated]";

            return string.IsNullOrWhiteSpace(text) ? "Page returned no readable content." : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseResults(string html)
    {
        var results = new List<SearchResult>();
        var resultPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?" +
            @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        foreach (Match m in resultPattern.Matches(html))
        {
            var rawUrl = WebUtility.HtmlDecode(m.Groups["url"].Value);
            // DuckDuckGo wraps URLs in a redirect; extract the real URL
            var uddgMatch = Regex.Match(rawUrl, @"uddg=(?<real>[^&]+)");
            var finalUrl = uddgMatch.Success
                ? WebUtility.UrlDecode(uddgMatch.Groups["real"].Value)
                : rawUrl;

            results.Add(new SearchResult
            {
                Title = StripTags(m.Groups["title"].Value),
                Url = finalUrl,
                Snippet = StripTags(m.Groups["snippet"].Value)
            });
        }

        return results;
    }

    private static string StripTags(string s) =>
        WebUtility.HtmlDecode(Regex.Replace(s, @"<[^>]+>", "")).Trim();

    private sealed class SearchResult
    {
        public string Title { get; init; } = "";
        public string Url { get; init; } = "";
        public string Snippet { get; init; } = "";
    }
}

using System.ComponentModel;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and body. Use this to record key findings as you research.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The content of the note")] string body)
    {
        _notes.Add(new Note(title, body));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("List all saved research notes so far.")]
    public string ListNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Body}"));
    }

    private sealed record Note(string Title, string Body);
}

