using System.ComponentModel;

namespace ResearchAgent.Tools;

public sealed class NoteTakingTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and body. Use this to record key findings as you research.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The content of the note")] string body)
    {
        _notes.Add(new Note(title, body));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("List all saved research notes so far.")]
    public string ListNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) =>
            $"--- Note {i + 1}: {n.Title} ---\n{n.Body}"));
    }

    private sealed record Note(string Title, string Body);
}

