using System.ClientModel;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run the agent.");
    return 1;
}

// --- Tools ---
var webSearch = new WebSearchTool();
var notes = new NoteTakingTool();

var tools = new AIFunctionFactory[]
    { }; // placeholder – we pass AIFunctions directly below

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(webSearch.FetchPage),
        AIFunctionFactory.Create(notes.SaveNote),
        AIFunctionFactory.Create(notes.ListNotes),
    ]
};

// --- Chat client with automatic function-calling ---
IChatClient client = new OpenAIClient(new ApiKeyCredential(apiKey))
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// --- System prompt ---
var systemMessage = """
    You are a research assistant agent. Your job is to deeply research a topic
    the user provides. Follow this workflow:

    1. Use SearchWeb to find relevant information from multiple angles.
    2. Use FetchPage to read promising articles in detail.
    3. Use SaveNote to record important facts, data, and quotes as you go.
    4. Perform multiple search rounds if needed to cover the topic well.
    5. Use ListNotes to review what you have collected.
    6. Finally, write a comprehensive summary of your findings, citing sources.

    Be thorough but concise. Aim for 3-5 search rounds before summarizing.
    """;

var history = new List<ChatMessage>
{
    new(ChatRole.System, systemMessage)
};

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (v1.0)       ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");

while (true)
{
    Console.Write("\n> ");
    var input = Console.ReadLine();

    if (string.IsNullOrWhiteSpace(input))
        continue;

    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    // Reset conversation for each new topic but keep the system prompt
    history = [history[0], new ChatMessage(ChatRole.User, input)];

    Console.WriteLine($"\nResearching: {input}\n");

    try
    {
        var response = await client.GetResponseAsync(history, chatOptions);

        // Append assistant response to history
        history.AddRange(response.Messages);

        Console.WriteLine("─── Research Summary ───────────────────");
        Console.WriteLine(response.Text);
        Console.WriteLine("────────────────────────────────────────");
    }
    catch (Exception ex)
    {
        Console.Error.WriteLine($"Error: {ex.Message}");
    }
}

Console.WriteLine("Goodbye!");
return 0;

